import { useState } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Loader2, CheckCircle2, AlertTriangle, XCircle, MapPin, Store } from "lucide-react";
import { useTranslation } from "react-i18next";
import { supabase } from "@/integrations/supabase/client";
import { useToast } from "@/hooks/use-toast";

interface ClaimRestaurantDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  restaurant: {
    id: string;
    name: string;
    address?: string;
  } | null;
}

type VerificationStatus = "idle" | "verifying" | "verified" | "manual_review" | "rejected" | "error";

const ClaimRestaurantDialog = ({ open, onOpenChange, restaurant }: ClaimRestaurantDialogProps) => {
  const { t } = useTranslation();
  const { toast } = useToast();
  const [taxId, setTaxId] = useState("");
  const [status, setStatus] = useState<VerificationStatus>("idle");
  const [result, setResult] = useState<{ confidence: number; company_name: string; reason: string; country: string } | null>(null);

  const handleSubmit = async () => {
    if (!taxId.trim() || !restaurant) return;

    setStatus("verifying");
    setResult(null);

    try {
      const { data, error } = await supabase.functions.invoke("verify-tax-id", {
        body: { tax_id: taxId.trim(), restaurant_id: restaurant.id },
      });

      if (error) throw error;

      if (data.error) {
        setStatus("error");
        toast({ title: t("common.error"), description: data.error, variant: "destructive" });
        return;
      }

      setResult(data);
      setStatus(data.status as VerificationStatus);

      if (data.status === "verified") {
        toast({
          title: t("claim.approvedToast"),
          description: data.reason,
        });
      }
    } catch (e: any) {
      console.error("Verification error:", e);
      setStatus("error");
      toast({ title: t("common.error"), description: e.message, variant: "destructive" });
    }
  };

  const handleClose = () => {
    if (status !== "verifying") {
      setTaxId("");
      setStatus("idle");
      setResult(null);
      onOpenChange(false);
    }
  };

  const getStatusIcon = () => {
    const s = status as string;
    if (s === "verifying") return <Loader2 className="w-12 h-12 text-primary animate-spin" />;
    if (s === "verified") return <CheckCircle2 className="w-12 h-12 text-green-600" />;
    if (s === "manual_review") return <AlertTriangle className="w-12 h-12 text-amber-500" />;
    if (s === "rejected" || s === "error") return <XCircle className="w-12 h-12 text-destructive" />;
    return null;
  };

  const getStatusMessage = () => {
    switch (status) {
      case "verifying": return t("claim.verifying");
      case "verified": return t("claim.verified");
      case "manual_review": return t("claim.manualReview");
      case "rejected": return t("claim.rejected");
      default: return "";
    }
  };

  if (!restaurant) return null;

  return (
    <Dialog open={open} onOpenChange={handleClose}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle>{t("claim.title")}</DialogTitle>
          <DialogDescription>{t("claim.description")}</DialogDescription>
        </DialogHeader>

        <div className="space-y-4">
          {/* Store info */}
          <div className="bg-secondary/50 rounded-lg p-3 space-y-2">
            <div className="flex items-center gap-2">
              <Store className="w-4 h-4 text-muted-foreground flex-shrink-0" />
              <span className="font-medium text-sm">{restaurant.name}</span>
            </div>
            {restaurant.address && (
              <div className="flex items-start gap-2">
                <MapPin className="w-4 h-4 text-muted-foreground flex-shrink-0 mt-0.5" />
                <span className="text-sm text-muted-foreground">{restaurant.address}</span>
              </div>
            )}
          </div>

          {/* Tax ID input */}
          {(status === "idle" || (status as string) === "error") ? (
            <div className="space-y-2">
              <Label htmlFor="tax-id">{t("claim.taxIdLabel")}</Label>
              <Input
                id="tax-id"
                placeholder={t("claim.taxIdPlaceholder")}
                value={taxId}
                onChange={(e) => setTaxId(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && taxId.trim() && handleSubmit()}
              />
              <p className="text-xs text-muted-foreground">{t("claim.autoDetectCountry")}</p>
              <Button onClick={handleSubmit} disabled={!taxId.trim()} className="w-full">
                {t("claim.verifyButton")}
              </Button>
            </div>
          ) : (
            /* Verification result */
            <div className="flex flex-col items-center gap-3 py-4">
              {getStatusIcon()}
              <p className="text-sm text-center font-medium">{getStatusMessage()}</p>
              {result && (
                <div className="w-full bg-secondary/30 rounded-lg p-3 space-y-1 text-xs">
                  {result.company_name && (
                    <p><span className="text-muted-foreground">{t("claim.company")}:</span> {result.company_name}</p>
                  )}
                  {result.country && (
                    <p><span className="text-muted-foreground">{t("claim.country")}:</span> {result.country}</p>
                  )}
                  {result.reason && (
                    <p className="text-muted-foreground mt-1">{result.reason}</p>
                  )}
                </div>
              )}
              {(status === "rejected" || (status as string) === "error") && (
                <Button variant="outline" onClick={() => { setStatus("idle"); setResult(null); }} className="mt-2">
                  {t("claim.tryAgain")}
                </Button>
              )}
              {(status === "verified" || status === "manual_review") && (
                <Button variant="outline" onClick={handleClose} className="mt-2">
                  {t("common.close", "关闭")}
                </Button>
              )}
            </div>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
};

export default ClaimRestaurantDialog;
